#include <stdio.h>
#include <stdint.h>

// Interrupt Descriptor Table entry structure
struct IDTEntry {
    uint16_t offset_low;
    uint16_t selector;
    uint8_t  ist;
    uint8_t  type_attr;
    uint16_t offset_mid;
    uint32_t offset_high;
    uint32_t reserved;
} __attribute__((packed));

// Function pointer type for interrupt handlers
typedef void (*interrupt_handler_t)(void);

// Global IDT table
struct IDTEntry idt[256];

// Install an interrupt handler
void install_interrupt_handler(uint8_t vector, 
                                interrupt_handler_t handler) {
    uint64_t handler_addr = (uint64_t)handler;

    idt[vector].offset_low = handler_addr & 0xFFFF;
    idt[vector].offset_mid = (handler_addr >> 16) & 0xFFFF;
    idt[vector].offset_high = (handler_addr >> 32) & 0xFFFF;
    idt[vector].selector = 0x08;  // Code segment selector
    idt[vector].type_attr = 0x8E; // Present, DPL=0, 32-bit interrupt gate
}

// Example keyboard interrupt handler
void keyboard_handler(void) {
    unsigned char status = inb(0x64);  // Read keyboard status
    if (status & 0x01) {               // Output buffer full
        unsigned char keycode = inb(0x60);  // Read keycode
        // Process keycode
    }
    outb(0x20, 0x20);  // Send End of Interrupt to PIC
}

int main() {
    install_interrupt_handler(33, keyboard_handler);  // IRQ1 = vector 33
    // Initialize PIC and enable interrupts
    return 0;
}

// PROGRAMMED I/O (POLLING) - INEFFICIENT
ALGORITHM PolledDataTransfer
BEGIN
    WHILE more_data_to_transfer DO
        // CPU continuously checks device status
        WHILE NOT device_ready() DO
            // Waste CPU cycles waiting
            nop  // No operation - just wait
        END WHILE

        // Device is ready, transfer data
        data = read_from_device()
        process(data)
    END WHILE
END ALGORITHM

// INTERRUPT-DRIVEN I/O - EFFICIENT
ALGORITHM InterruptDrivenIO
BEGIN
    // Initialize - start I/O and return immediately
    setup_device_for_transfer()
    device_buffer_address = memory_buffer
    device_control = START_TRANSFER

    // Main program continues executing
    DO_OTHER_WORK()

    // Later, interrupt occurs when device is ready
    INTERRUPT SERVICE ROUTINE
        SAVE_STATE()

        WHILE device_has_more_data() DO
            data = read_from_device()
            write_to_memory(data)
        END WHILE

        // Check if more transfers needed
        IF more_transfers_needed THEN
            restart_transfer()
        END IF

        RESTORE_STATE()
        RETURN_FROM_INTERRUPT()
    END INTERRUPT SERVICE ROUTINE
END ALGORITHM

